INSERT INTO `api_schemas` VALUES (1,'prior-auth-request-inbound-api','1.0.7','prior-auth-request-inbound-api.raml','#%RAML 1.0\ntitle: Prior Auth Request API\nversion: v1\ndescription: Use the Prior Auth Request API to authorize the provisioning of products or services to a patient and manage healthcare processes, such as claim inquiry and claim submission.\n\nmediaType:\n  - application/fhir+json\nprotocols:\n  - https\n\nuses:\n  resourceTypes: /resources/fhir-r4-resource-types-library.raml\n  pasclaimresponse: /modules/fhir-r4-pasclaimresponse-library/fhir-r4-pasclaimresponse-library.raml\n  pasclaimrequest: /modules/fhir-r4-pasclaimrequest-library/fhir-r4-pasclaimrequest-library.raml\n  pasinquiryrequest: /modules/fhir-r4-pasinquiryrequest-library/fhir-r4-pasinquiryrequest-library.raml\n  pasinquiryresponse: /modules/fhir-r4-pasinquiryresponse-library/fhir-r4-pasinquiryresponse-library.raml\n  pasclaimattachmentrequest: /modules/fhir-r4-pasclaimattachment-library/fhir-r4-pasclaimattachment-library-request.raml\n  pasclaimattachmentresponse: /modules/fhir-r4-pasclaimattachment-library/fhir-r4-pasclaimattachment-library-response.raml\n\n/$submit:\n\n  type: {resourceTypes.fhirResourceType: {\n      postDisplayName: Create a claim submission request,\n      postRequestExample : !include examples/requests/pasclaimbundle_request.json,\n      postResponseExample : !include examples/responses/pasclaimbundle_response.json,\n      locationHeaderExample: http://xxx/$PriorAuthClaim,\n      errorResponse : !include examples/errorResponses/error_resource.json,\n      errorResponseSingle : !include examples/errorResponses/error_resource_operationoutcome.json,\n      responseBundleName : pasclaimresponse.PASClaimResponseBundle,\n      requestBundleName : pasclaimrequest.PASClaimRequestBundle\n    }\n  }\n\n/$inquiry:\n\n  type: {\n    resourceTypes.fhirResourceType: {\n      postDisplayName: Create a claim inquiry request,\n      postRequestExample : !include examples/requests/Bundle-PASClaimInquiryBundleExample.json,\n      postResponseExample : !include examples/responses/Bundle-PASClaimInquiryResponseBundleExample.json,\n      locationHeaderExample: http://xxx/$PriorAuthClaimInquiry,\n      errorResponse : !include examples/errorResponses/error_resource.json,\n      errorResponseSingle : !include examples/errorResponses/error_resource_operationoutcome.json,\n      responseBundleName: pasinquiryresponse.PASClaimInquiryResponseBundle,\n      requestBundleName: pasinquiryrequest.PASClaimInquiryRequestBundle\n    }\n  }\n\n/$submit-attachment:\n  type: {resourceTypes.fhirAttachmentResourceType: {\n      postRequestExample : !include examples/requests/submit-attachment-request.json, \n      postResponseExample : !include examples/responses/submit-attachment-response.json,\n      errorResponse : !include examples/errorResponses/bad-request.json,\n      errorResponseSingle : !include examples/errorResponses/error_resource_operationoutcome.json,\n      responseBundleName : pasclaimattachmentresponse.OperationOutcome,\n      requestBundleName : pasclaimattachmentrequest.Parameters\n    }\n  }','2026-04-02 16:48:40',1,0,7),(2,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasclaimattachment-library/fhir-r4-pasclaimattachment-library-response.raml','#%RAML 1.0 Library\n\ntypes:\n  OperationOutcome:\n    type: object\n    properties:\n      resourceType:\n        enum:\n          - OperationOutcome\n      issue: Issue[]\n    \n  Issue:\n    type: object\n    properties:\n      severity:\n        enum:\n          - information\n          - warning\n          - error\n          - success\n      code: string\n      details:\n        type: object\n        properties:\n          text: string\n      diagnostics?: string\n\n    ','2026-04-02 16:48:40',1,0,7),(3,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasclaimresponse-library/fhir-r4-pasclaimresponse-library.raml','#%RAML 1.0 Library\n\nuses:\n  FHIR_commons: ../fhir-r4-common-library/fhir-r4-common-library.raml\n  \ntypes:  \n\n               \n  PASClaimResponseBundle:\n    type: FHIR_commons.Bundle\n    properties:\n      entry?: (FHIR_commons.PASQuestionnaireResponse | FHIR_commons.PASClaimResponseEntry | FHIR_commons.PASOrganizationEntry | FHIR_commons.PASPractitionerEntry | FHIR_commons.PASCoverageEntry | FHIR_commons.PASPatientEntry)[]\n','2026-04-02 16:48:40',1,0,7),(4,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasinquiryresponse-library/fhir-r4-pasinquiryresponse-library.raml','#%RAML 1.0 Library\n\nuses:\n  FHIR_commons: ../fhir-r4-common-library/fhir-r4-common-library.raml\n  \ntypes:  \n               \n  PASClaimInquiryResponseBundle:\n    type: FHIR_commons.Bundle\n    properties:\n      entry?: (FHIR_commons.PASQuestionnaireResponse | FHIR_commons.PASClaimResponseEntry | FHIR_commons.PASOrganizationEntry | FHIR_commons.PASPractitionerEntry | FHIR_commons.PASCoverageEntry | FHIR_commons.PASPatientEntry)[]\n','2026-04-02 16:48:40',1,0,7),(5,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasclaimattachment-library/fhir-r4-pasclaimattachment-library-request.raml','\n#%RAML 1.0 Library\nuses:\n  FHIR_commons: ../fhir-r4-common-library/fhir-r4-common-library.raml\n\ntypes:\n  Identifier:\n    type: object\n    description: Other identifiers for the document\n    properties:\n      system?: string\n      value: string\n  \n  AttachmentPart:\n    type: object\n    properties:\n      name:\n        enum:\n          - Type\n          - LineItem\n          - Content\n          - Code\n      valueCode?: string\n      valueString?: string\n      valueIdentifier?: Identifier\n      valueCodeableConcept?: FHIR_commons.CodeableConcept\n      resource?:\n        type: object\n        description: Either a DocumentReference or Binary FHIR resource.\n\n  Parameter:\n    type: object\n    properties:\n      name:\n        enum:\n          - TrackingId\n          - AttachTo\n          - PayerId\n          - OrganizationId\n          - ProviderId\n          - MemberId\n          - ServiceDate\n          - Attachment\n      valueCode?: string\n      valueIdentifier?: Identifier\n      valueBoolean?: boolean\n      valueDateTime?: FHIR_commons.dateTime\n      part?: AttachmentPart[]\n\n  Parameters:\n    type: object\n    properties:\n      resourceType:\n        enum:\n          - Parameters\n      parameter: Parameter[] \n','2026-04-02 16:48:40',1,0,7),(6,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasclaimrequest-library/fhir-r4-pasclaimrequest-library.raml','#%RAML 1.0 Library\n\nuses:\n  FHIR_commons: ../fhir-r4-common-library/fhir-r4-common-library.raml\n  \ntypes:\n\n\n  PASClaimRequestBundle:\n    type: FHIR_commons.Bundle\n    properties:\n      entry?: (FHIR_commons.PASQuestionnaireResponse | FHIR_commons.PASClaimRequestEntry | FHIR_commons.PASOrganizationEntry | FHIR_commons.PASPractitionerEntry | FHIR_commons.PASPatientEntry | FHIR_commons.PASCoverageEntry | FHIR_commons.PASLocationEntry | FHIR_commons.PASServiceRequestEntry | FHIR_commons.PASQuestionnaireResponseBundle)[]','2026-04-02 16:48:40',1,0,7),(7,'prior-auth-request-inbound-api','1.0.7','resources/fhir-r4-resource-types-library.raml','#%RAML 1.0 Library\n\nuses:\n  FHIR_commons: ../modules/fhir-r4-common-library/fhir-r4-common-library.raml\n  pasclaimresponse: ../modules/fhir-r4-pasclaimresponse-library/fhir-r4-pasclaimresponse-library.raml\n\nresourceTypes:\n\n  fhirResourceType:\n    post:\n      displayName: <<postDisplayName>>\n      description: |\n        Creates a resource to generate a claim submission or claim inquiry request with prior authorization.\n      is: [ create : {\n                      postRequestExample: <<postRequestExample>>,\n                      postResponseExample: <<postResponseExample>>,\n                      errorResponse: <<errorResponse>> ,\n                      errorResponseSingle: <<errorResponseSingle>>,\n                      requestBundleName: <<requestBundleName>>,\n                      responseBundleName: <<responseBundleName>>\n                      }]\n\n  fhirAttachmentResourceType:\n    post:\n      description: |\n        Submit attachments and related metadata using a FHIR-like Parameters resource. \n      is: [ create : { \n                      postRequestExample: <<postRequestExample>>, \n                      postResponseExample: <<postResponseExample>>, \n                      errorResponse: <<errorResponse>> ,\n                      errorResponseSingle: <<errorResponseSingle>>,\n                      requestBundleName: <<requestBundleName>>,\n                      responseBundleName: <<responseBundleName>>\n                      }] \n\ntraits:\n  create:  \n    headers:\n      Accept:\n        type: string\n        required: false\n        enum: [\"application/fhir+json\"] \n      Access-Token:\n        type: string\n        description: Salesforce org access token\n        example: Bearer asvg473tebdjebdsakl!jsjndkcmldcmdcmedj3o9.asd\n      Instance-Domain-Name:\n        type: string\n        description: Instance domain name of the salesforce org\n        example: orgid.salesforce.com\n    body:\n        application/fhir+json:\n          type: <<requestBundleName>>\n          example: <<postRequestExample>>\n    responses:\n      201:\n        description: No match was found. Resource created.\n        body:\n          application/fhir+json:\n            type: <<responseBundleName>>\n            example: <<postResponseExample>>\n      500:\n        body:\n          application/fhir+json:\n            type: FHIR_commons.OperationOutcome\n            example: <<errorResponseSingle>>\n\n      400:\n        body:\n          application/fhir+json:\n            example: <<errorResponse>>\n\n      404:\n        body:\n          application/fhir+json:\n            example: <<errorResponse>>\n','2026-04-02 16:48:41',1,0,7),(8,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-pasinquiryrequest-library/fhir-r4-pasinquiryrequest-library.raml','#%RAML 1.0 Library\n\nuses:\n  FHIR_commons: ../fhir-r4-common-library/fhir-r4-common-library.raml\n  \ntypes:\n\n  PASClaimInquiryRequestBundle:\n    type: FHIR_commons.Bundle\n    properties:\n      entry?: (FHIR_commons.PASClaimRequestEntry | FHIR_commons.PASOrganizationEntry | FHIR_commons.PASPractitionerEntry | FHIR_commons.PASPatientEntry | FHIR_commons.PASCoverageEntry | FHIR_commons.PASLocationEntry | FHIR_commons.PASServiceRequestEntry)[]','2026-04-02 16:48:41',1,0,7),(9,'prior-auth-request-inbound-api','1.0.7','modules/fhir-r4-common-library/fhir-r4-common-library.raml','#%RAML 1.0 Library \n# This file is alphabetically sorted, please add elements accordingly\ntypes:\n  positiveInt:\n    type: integer\n    description: Specifies any positive integer (>= 1) with regex - +?[1-9][0-9]*.\n    minimum: 1\n\n  Meta:\n    description: |\n      Holds the  set of metadata (meta element) of the type Meta that each resource contains. Gives technical and workflow context to the resource. Though the metadata items are optional, some or all of the items are required in certain implementations or contexts.\n    type: object\n    properties:\n      profile?:\n        description: Specifies the profiles that a resource claims to conform to.\n        type: canonical[]\n        \n  code:\n    type: string\n    description: |\n      Indicates that the value is taken from a set of controlled strings defined elsewhere. See <a href=\"http://hl7.org/fhir/STU3/terminologies.html\" target=\"_blank\">Using codes</a>.\n      A code is restricted to a string, which has at least one character and no leading or trailing whitespace, and with no whitespace other than the single spaces in the content.\n    pattern: ^[^\\s]+([\\s]+[^\\s]+)*\n\n  id:\n    type: string\n    pattern: ^[A-Za-z0-9\\-\\.]{1,64}$\n    description: |\n      Represents any combination of upper or lower case ASCII letters (\'A\'..\'Z\', and \'a\'..\'z\'), numerals (\'0\'..\'9\'), \'-\', and \'.\', with a length limit of 64 characters. Possible patterns are integer, an unprefixed OID, UUID, or any other identifier pattern that meets the constraints.\n\n  DomainResource:\n      type: Resource\n      description: A resource with narrative, extensions, and contained resources\n      properties:\n        text?:\n          type: Narrative\n          description: Text summary of the resource, for human interpretation      \n        contained?:\n          type: Resource[]\n          description: Contained, inline Resources\n    \n  Annotation:\n    type: Element\n    description: Text node with attribution\n    properties:\n      time?:\n        type: dateTime\n        description:  When the annotation was made\n      text:\n        type: markdown\n        description: The annotation - text content (as markdown)\n  \n  markdown:\n    type: Extension\n    properties:\n      url: uri\n  \n  QuestionnaireResponse:\n    type: Resource\n    properties:\n      id: \n        type: string\n      resourceType:\n        type: string\n        enum:\n          - QuestionnaireResponse\n\n  ClaimResponse:\n    type: Resource\n    properties:\n      resourceType:\n        type: string\n        enum: [ClaimResponse]\n      id?:\n        description: An id for the claimresponse\n        type: id     \n      identifier?:\n        description: An identifier for the claimresponse\n        type: Identifier[]\n      text?:\n        description: Text summary of the resource, for human interpretation\n        type: Narrative \n      contained?:\n        description: Contained, inline Resources\n        type: Resource[]\n      status:\n        description: active | cancelled | draft | entered-in-error\n        type: code\n        enum: [active, cancelled, draft, entered-in-error]\n      type:\n        description: More granular claim type\n        type: CodeableConcept\n        properties:\n          coding?:\n            description: Code defined by a terminology system\n            type: array\n            items:\n              type: Coding\n              properties:\n                code?:\n                  type: code\n                  enum: [institutional, oral, pharmacy, professional, vision]     \n      subType?:\n        description: More granular claim type\n        type: CodeableConcept\n        properties:\n          coding?:\n            description: Code defined by a terminology system\n            type: array\n            items:\n              type: Coding\n              properties:\n                code?:\n                  type: code\n                  enum: [ortho, emergency]\n      use:\n        description: claim | preauthorization | predetermination\n        type: code\n        enum: [claim, preauthorization, predetermination]   \n      patient:\n        description: The recipient of the products and services\n        type: Reference   \n      created:\n        description:  Response creation date\n        type: dateTime\n      insurer:\n        description: Party responsible for reimbursement\n        type: Reference\n      requestor?:\n        description: Party responsible for the claim\n        type: Reference\n      request?:\n        description: Reference to PASClaim\n        type: Reference            \n      outcome:\n        description: queued | complete | error | partial\n        type: code\n        enum: [queued, complete, error, partial]\n      disposition?:\n        description: Disposition Message\n        type: string\n      preAuthRef?:\n        description: Preauthorization reference\n        type: string\n      preAuthPeriod?:\n        description:  Preauthorization reference effective period\n        type: Period\n      payeeType?:\n        description: Party to be paid any benefits payable\n        type: CodeableConcept\n        properties:\n          coding?:\n            description: Code defined by a terminology system\n            type: array\n            items:\n              type: Coding\n              properties:\n                code?:\n                  type: code\n                  enum: [subscriber, provider, other]\n      error?:\n        description: All insurances for order requests\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description: Unique id for inter-element referencing\n              type: string\n            itemSequence?:\n              description: Item sequence number\n              type: positiveInt\n            detailSequence?:\n              description: Detail sequence number\n              type: positiveInt\n            subDetailSequence?:\n              description: Subdetail sequence number\n              type: positiveInt\n            code: \n              description: Error code detailing processing issues\n              type: CodeableConcept         \n      insurance?:\n        description: All insurances for order requests\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description: Unique id for inter-element referencing\n              type: string\n            businessArrangement?:\n              description: Additional provider contract number\n              type: string\n            claimResponse?:\n              description: Adjudication results\n              type: Reference\n            sequence:\n              description: Insurance instance identifier\n              type: positiveInt\n            focal:\n              description: Coverage to be used for adjudication\n              type: boolean\n            coverage:\n              description: Reference to Coverage Resource\n              type: Reference                                    \n      item?:\n        description: Adjudication for claim line items\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description:  Unique id for inter-element referencing\n              type: string\n            extension-itemPreAuthIssueDate?:\n              description: review action\n              type: date\n            extension-itemPreAuthPeriod?:\n              description: Extension\n              type: Period\n            extension-itemTraceNumber?:\n              description: Uniquely identifies this claim item.\n              type: Identifier[]\n            extension-authorizationNumber?:\n              description: A string assigned by the UMO to an authorized review outcome associated with this service item.\n              type: string\n            extension-administrationReferenceNumber?:\n              description: A string assigned by the UMO to the original disallowed review outcome associated with this service item.\n              type: string\n            extension-itemAuthorizedDate?:\n              description: The date/period by which the item that is pre-authorized must be completed.\n              type: dateTime | Period\n            itemSequence:\n              description: Claim item instance identifier\n              type: positiveInt\n            noteNumber?:\n              description: Applicable note numbers\n              type: positiveInt[]\n            adjudication:\n              type: array\n              items:\n                type: BackboneElement\n                properties:\n                  id?:\n                    description: Unique id for inter-element referencing\n                    type: string\n                  category:\n                    description: Type of adjudication information\n                    type: CodeableConcept\n                    properties:\n                      coding?:\n                        description: Code defined by a terminology system\n                        type: array\n                        items:\n                          type: Coding\n                          properties:\n                            code?:\n                              type: code\n                              enum: [submitted, copay, eligible, deductible, unallocdeduct, eligpercent, tax, benefit]\n                  reason?:\n                    description: Explanation of adjudication outcome\n                    type: CodeableConcept\n                    properties:\n                      coding?:\n                        description: Code defined by a terminology system\n                        type: array\n                        items:\n                          type: Coding\n                          properties:\n                            code?:\n                              type: code\n                              enum: [ar001, ar002]\n                  amount?:\n                    description: Monetary amount\n                    type: Money\n                  value?:\n                    description: Non-monetary value\n                    type: decimal\n            detail?:\n              type: array\n              items:\n                type: BackboneElement\n                properties:\n                  id?:\n                    description: Unique id for inter-element referencing\n                    type: string\n                  detailSequence:\n                    description: Claim detail instance identifier\n                    type: positiveInt\n                  noteNumber?:\n                    description: Applicable note numbers\n                    type: positiveInt[]\n                  subDetail?:\n                    description: Adjudication for claim sub-details\n                    type: array\n                    items:\n                      type: BackboneElement\n                      properties:\n                        id?:\n                          description: Unique id for inter-element referencing\n                          type: string\n                        subDetailSequence:\n                          description: Claim sub-detail instance iden