                   type: code\n                          enum: [C, E, F, I, N, S, U]\n            name?:\n              description: A name associated with the contact person\n              type: HumanName\n            address?:\n              description: Address for the contact person\n              type: Address\n            telecom?:\n              description: A contact detail for the person\n              type: ContactPoint[]\n            gender?:\n              description: male | female | other | unknown\n              type: code\n              enum: [male, female, other, unknown]\n            organization?:\n              description: Organization that is associated with the contact\n              type: Reference\n            period?:\n              description: The period during which this contact person or organization is valid to be contacted relating to this patient\n              type: Period\n      managingOrganization?:\n        description: Organization that is the custodian of the patient record\n        type: Reference\n      generalPractitioner?:\n        description: Patient\'s nominated primary care provider\n        type: Reference[]\n      communication?:\n        description: A language which may be used to communicate with the patient about his or her health\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description: Unique id for inter-element referencing\n              type: string\n            language:\n              description: The language which can be used to communicate with the patient about his or her health\n              type: CodeableConcept\n            preferred?:\n              description: Language preference indicator\n              type: boolean\n      link?:\n        description: Link to another patient resource that concerns the same actual person\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description: Unique id for inter-element referencing\n              type: string\n            other:\n              description: The other patient or related person resource that the link refers to\n              type: Reference\n            type:\n              description: replaced-by | replaces | refer | seealso\n              type: code\n              enum: [replaced-by,  replaces,  refer, seealso]\n\n  Location:\n    type: Resource\n    properties:\n      resourceType:\n        type: string\n        enum: [Location]\n      id?:\n        description: Logical id of the location\n        type: id\n      identifier?:\n        description: Unique code or number identifying the location to its users\n        type: Identifier[]\n      text?:\n        description: Text summary of the resource, for human interpretation\n        type: Narrative\n      contained?:\n        description: Contained, inline Resources\n        type: Resource[]\n      status?:\n        description: active | suspended | inactive\n        type: code\n        enum: [active, suspended, inactive]\n      operationalStatus?:\n        description: The operational status of the location (typically only for a bed/room)\n        type: Coding\n        properties:\n          code?:\n            type: code\n            enum: [C, H, I, K, O , U]\n      name?:\n        description: Name of the location as used by humans\n        type: string\n      alias?:\n        description: A list of alternate names that the location is known as, or was known as, in the past\n        type: string[]\n      description?:\n        description: Additional details about the location that could be displayed as further information to identify the location beyond its name\n        type: string\n      mode?:\n        description: instance | kind\n        type: code\n        enum: [instance, kind]\n      telecom?:\n        description: Contact details of the location\n        type: ContactPoint[]\n      address?:\n        description: Physical location\n        type: Address\n      physicalType?:\n        description: Physical form of the location\n        type: CodeableConcept\n      position?:\n        description:  The absolute geographic location\n        type: BackboneElement\n        properties:\n          longitude:\n            description:  Longitude with WGS84 datum\n            type: decimal\n          latitude:\n            description: Latitude with WGS84 datum\n            type: decimal\n          altitude?:\n            description: Altitude with WGS84 datum\n            type: decimal\n      managingOrganization?:\n        description: Organization responsible for provisioning and upkeep\n        type: Reference\n      endpoint?:\n        description: Technical endpoints providing access to services operated for the location\n        type: Reference[]\n      type?:\n        description: Type of function performed\n        type: CodeableConcept\n        properties:\n          coding?:\n            description: Code defined by a terminology system\n            type: array\n            items:\n              type: Coding\n              properties:\n                code?:\n                  type: code\n                  enum: [DX, CVDX, CATH, ECHO, GIDX, ENDOS, RADDX, RADO, RNEU, HOSP, CHR, GACH, MHSP, PSYCHF, RH, RHAT, RHII, RHMAD, RHPI, RHPIH, RHPIMS, RHPIVS, RHYAD, HU, BMTU, CCU, CHEST, EPIL, ER, ETU, HD, HLAB, INLAB, OUTLAB, HRAD, HUSCS, ICU,PEDICU, PEDNICU, INPHARM, MBL, NCCS, NS, OUTPHARM, PEDU, PHU, RHU, SLEEP, NCCF, SNF, OF, ALL, AMPUT, BMTC, BREAST, CANC, CAPC, CARD, PEDCARD, COAG, CRS, DERM, ENDO, PEDE, ENT, FMC, GI, PEDGI, GIM, GYN, HEM, PEDHEM, HTN, IEC, INFD, PEDID, INV, LYMPH, MGEN, NEPH, PEDNEPH, NEUR, OB, OMS, ONCL, PEDHO, OPH, OPTC, ORTHO, HAND, PAINCL, PC, PEDC, PEDRHEUM, POD, PREV, PROCTO, PROFF, PROS, PSI, PSY, RHEUM, SPMED, SU, PLS, URO, TR, TRAVEL, WND, RTF, PRC, SURF, DADDR, MOBL, AMB, PHARM, ACC, COMM, CSC, PTRES, SCHOOL, UPC, WORK]\n      partOf?:\n        description: Another Location this one is physically a part of\n        type: Reference\n      hoursOfOperation?:\n        description: What days/times during a week is this location usually open\n        type: array\n        items:\n          type: BackboneElement\n          properties:\n            id?:\n              description: Unique id for inter-element referencing\n              type: string\n            daysOfWeek?:\n              description: mon | tue | wed | thu | fri | sat | sun\n              type: array\n              items:\n                type: code\n                enum: [mon, tue, wed, thu, fri, sat, sun]\n            allDay?:\n              description: The Location is open all day\n              type: boolean\n            openingTime?:\n              description: Time that the Location opens\n              type: time\n            closingTime?:\n              description: Time that the Location closes\n              type: time\n      availabilityExceptions?:\n        description: Description of availability exceptions\n        type: string\n\n  ServiceRequest:\n    type: DomainResource\n    properties:\n      resourceType:\n        type: string\n        enum: [ServiceRequest]\n      identifier?:\n        description: Identifiers assigned to this order\n        type: Identifier[]\n      instantiatesCanonical?:\n        description: Instantiates FHIR protocol or definition\n        type: canonical[]\n      instantiatesUri?:\n        description: Instantiates external protocol or definition\n        type: uri[]\n      basedOn?:\n        description: What request fulfills\n        type: Reference[]\n      replaces?:\n        description: What request replaces\n        type: Reference[]\n      requisition?:\n        description: Composite Request ID\n        type: Identifier\n      status:\n        description: draft | active | on-hold | revoked | completed | entered-in-error | unknown\n        type: code\n        enum: [draft , active , on-hold , revoked , completed , entered-in-error , unknown]\n      intent:\n        description: proposal | plan | directive | order | original-order | reflex-order | filler-order | instance-order | option\n        type: code\n        enum: [proposal , plan , directive , order , original-order , reflex-order , filler-order , instance-order , option]\n      category?:\n        description: Classification of service\n        type: CodeableConcept[]\n      priority?:\n        description: routine | urgent | asap | stat\n        type: code\n        enum: [routine , urgent , asap , stat]\n      doNotPerform?: \n        description: True if service/procedure should not be performed\n        type: boolean\n      quantityQuantity?:\n        description: Service amount\n        type: Quantity\n      code?:\n        description: What is being requested/ordered\n        type: CodeableConcept\n      orderDetail?:\n        description: Additional order information\n        type: CodeableConcept[]\n      occurencePeriod?:\n        description: When service should occur\n        type: Period\n      subject:\n        description: Individual or Entity the service is ordered for\n        type: Reference\n      encounter?:\n        description: Encounter in which the request was created\n        type: Reference\n      authoredOn?:\n        description: Date request signed\n        type: dateTime\n      requester?:\n        description: Who/what is requesting service\n        type: Reference\n      performerType?:\n        description: Performer role\n        type: CodeableConcept\n      performer?:\n        description: Requested performer\n        type: Reference[]\n      locationCode?:\n        description:  Requested location\n        type: CodeableConcept[]\n      locationReference?:\n        description: Requested location\n        type: Reference[]\n      reasonCode?:\n        description: Explanation/Justification for procedure or service\n        type: CodeableConcept[]\n      reasonReference?:\n        description: Explanation/Justification for service or service\n        type: Reference[]\n      insurance?:\n        description: Associated insurance coverage\n        type: Reference[]\n      supportingInfo?:\n        description:  Additional clinical information\n        type: Reference[]\n      specimen?:\n        description: Procedure Samples\n        type: Reference[]\n      bodySite?:\n        description: Location on Body\n        type: CodeableConcept[]\n      note?:\n        description: Comments\n        type: Annotation[]\n      patientInstruction?:\n        description: Patient or consumer-oriented instructions\n        type: string\n      relevantHistory?:\n        description: Request provenance\n        type: Reference[]\n\n  PASClaimRequestEntry:\n    type: Entry\n    properties:\n      resource: Claim\n      \n  PASOrganizationEntry:\n    type: Entry\n    properties:\n      resource: Organization\n      \n  PASPractitionerEntry:\n    type: Entry\n    properties:\n      resource: Practitioner\n      \n  PASCoverageEntry:\n    type: Entry\n    properties:\n      resource: Coverage\n      \n  PASLocationEntry:\n    type: Entry\n    properties:\n      resource: Location\n      \n  PASPatientEntry:\n    type: Entry\n    properties:\n      resource: Patient\n\n  PASServiceRequestEntry:\n    type: Entry\n    properties:\n      resource: ServiceRequest      \n           \n                                          \n                                    \n  date:\n    type: string\n    description: |\n      Specifies a date or partial date (year or year with month) without a time zone. Dates must be valid dates.\n    pattern: ^[0-9]{4}(-(0[1-9]|1[0-2])(-(0[0-9]|[1-2][0-9]|3[0-1]))?)?$\n    example: 1970-08-07\n    \n  decimal:\n    type: number\n    description: |\n      Specifies the rational numbers that have a decimal representation. See below about the precision of the number.\n      Regex: -?(0|[1-9][0-9]*)(\\.[0-9]+)?([eE][+-]?[0-9]+)?\n  \n  Attachment:\n    description: Specifies the content in a format that\'s defined elsewhere.\n    type: Element\n    properties:   \n      contentType?:\n        description: Specifies the mime type of the content, such as a charset.\n        type: code\n      language?:\n        description: Specifies the human language of the content (BCP-47).\n        type: code\n      title?:\n        description: Specifies the label to display in place of the data.\n        type: string\n      creation?:\n        description: Specifies the date when the attachment was first created.\n        type: dateTime\n      height?:\n        description: Specifies the height of the image in pixels.\n        type: positiveInt\n      width?:\n        description: Specifies the width of the image in pixels.\n        type: positiveInt\n      frames?:\n        description: Specifies the number of frames if > 1.\n        type: positiveInt\n      duration?:\n        description: Specifies the length in seconds.\n        type: decimal\n      pages?:\n        description: Specifies the number of printed pages.\n        type: positiveInt\n        \n  Address:\n    type: Element\n    description: |\n      Specifies an address that\'s expressed using postal conventions as opposed to GPS or other location definition formats. Usage of address data type can include delivering mail and visiting locations that aren\'t valid for mail delivery.\n      There are a variety of postal address formats defined around the world.\n    properties:\n      use?:\n        description: Specifies the usage of the address. Possible values are home, work, temp, old, and billing.\n        type: code\n        enum: [home, work, temp, old, billing]\n      type?:\n        description: Specifies the address type. Possible values are postal, physical, and both.\n        type: code\n        enum: [postal, physical, both]\n      text?:\n        description: Specifies the text representation of the address.\n        type: string\n      line?:\n        description: Specifies the street name, number, direction, and P.O. Box.\n        type: string[]\n      city?:\n        description: Specifies the name of city or town.\n        type: string\n      district?:\n        description: Specifies the district name (aka county).\n        type: string\n      state?:\n        description: Specifies the sub-unit of country (abbreviations are accepted).\n        type: string\n      postalCode?:\n        description: Specifies the postal code of the area.\n        type: string\n      country?:\n        description: Specifies the country, which can be an ISO 3166 2 or 3-letter code.\n        type: string\n      period?:\n        description: Specifies the time period for the usage of the address.\n        type: Period\n        \n  adjudication:\n    description: Specifies the adjudication for the claim line items.\n    type: array\n    items:\n      type: BackboneElement\n      properties:\n        id?:\n          description: Specifies the unique ID for the inter-element referencing.\n          type: string\n        category:\n          description: Specifies the category of the review action.\n          type: CodeableConcept\n          properties:\n            coding?:\n              description: Code defined by a terminology system\n              type: array\n              items:\n                type: Coding\n                properties:\n                  code?:\n                    type: code\n                    enum: [submitted, copay, eligible, deductible, unallocdeduct, eligpercent, tax, benefit]\n        reason?:\n          description: Specifies the reason for the review action.\n          type: CodeableConcept\n          properties:\n            coding?:\n              description: Code defined by a terminology system\n              type: array\n              items:\n                type: Coding\n                properties:\n                  code?:\n                    type: code\n                    enum: [ar001, ar002]\n        amount?:\n          description: Specifies the monetary amount.\n          type: Money\n        value?: \n          description: Specifies the non-monetary value.\n          type: decimal\n  \n  Money:\n    type: Element\n    description:\n    properties:\n      value?: \n        description: Specifies the numerical value with implicit precision.\n        type: decimal\n      currency?: \n        description: Specifies the ISO 4217 currency code.\n        type: code\n\n  BackboneElement:\n    type: Element\n    properties:\n      modifierExtension?:\n        description: Specifies the modifier extensions.\n        type: Extension[]\n    \n  Bundle:\n    description: |\n      Contains a collection of resources.\n      + Rule: total only for search results or history.\n      + Rule: entry.search only for a search request.\n      + Rule: entry.request mandatory for batch, transaction, or history, else prohibited.\n      + Rule: entry.response mandatory for batch-response, transaction-response, or history, else prohibited.\n      + Rule: FullUrl must be unique in a bundle, or else entries with the same fullUrl must have different meta.versionId (except in history bundles).\n      + Rule: A document must have an identifier with a system and a value.\n      + Rule: A document must have a date.\n      + Rule: A document must have a Composition resource as the first resource.\n      + Rule: A message must have a MessageHeader resource as the first resource.\n      Elements defined in Ancestors: id, meta, implicitRules, and language.\n    properties:\n      type:\n        type: code\n        description: document | message | transaction | transaction-response | batch | batch-response | history | searchset | collection\n        enum: [document, message, transaction,  transaction-response, batch, batch-response,  history, searchset, collection]\n      id?:\n        type: id\n        description: Specifies the ID of the artifact.\n      total?:\n        type: unsignedInt\n        description: Specifies the number of matches with the search results.\n      meta?:\n        description: |\n          Holds the  set of metadata (meta element) of the type Meta that each resource contains. Gives technical and workflow context to the resource. Though the metadata items are optional, some or all of the items are required in certain implementations or contexts.\n        properties:\n          lastUpdated?:\n            description: Specifies the date when the record was last updated.\n            type: instant\n      link?:\n        description: Specifies the links related to the resource bundle.\n        type: array\n        items:\n          properties:\n            relation:\n              type: string\n              description: Specifies how this resource bundle link relates at the parent level. To know more about link relations, see <a href=\"http://www.iana.org/assignments/link-relations/link-relations.xhtml#link-relations-1\" target=\"_blank\">Link relations</a>.\n            url:\n              type: uri\n              description: Specifies the reference details of the link.\n      entry?: \n        type: array\n        description: |\n          An entry in the bundle includes a resource or information.\n          + Rule: must be a resource unless there\'s a request or response.\n          + Rule: fullUrl cannot be a version-specific reference.\n          For bundles of the document and message types, the first resource must be Composition and MessageHeader resources, respectively. For all bundles, the meaning of the order of entries depends on the bundle type.\n        items:\n          type: Entry\n      signature?:\n        type: Signature\n  \n  Signature:\n    description: |\n      Represents an electronic representation of a signature and its supporting context in a FHIR accessible form.\n      The signature can be a cryptographic type (XML DigSig or a JWT), which is able to provide a non-repudiation proof, or a graphical image that represents a signature or a signature process.\n    properties:\n      type:\n        description: Specifies the reason for the entity to sign the object(s).\n        type: array\n        items: Coding\n      when:\n        description: Specifies when the signature was created.\n        type: instant\n      who:\n        description: Specifies who signed the object(s).\n        type: Reference\n      onBehalfOf?:\n        description: Specifies the party that\'s represented.\n        type: Reference\n      targetFormat?:\n        type: code\n        description:  Specifies the technical format of the signed resources.\n      sigFormat?:\n        type: code\n        description: Specifies the technical format of the signature.\n      data?:\n        description: Specifies the actual signature content, such as XML DigSig. JWT, picture, and so on.\n        type: base64Binary \n\n  base64Binary:\n    type: string\n    pattern: (\\s*([0-9a-zA-Z\\+\\=]){4}\\s*)+\n    description: |\n      There\'s no specified upper limit to the size of a binary, but systems must impose some implementation-based limit to the supported size. This information requires clear documentation, though there\'s no computable for information at this time.\n      \n  \n    \n  CodeableConcept:\n    type: object\n    description: |\n      Represents a value that\'s supplied by providing a reference to one or more terminologies or ontologies, but is also defined by the provision of text.\n      The CodeableConcept type is a common pattern in healthcare data.\n    properties:\n      coding?:\n        description: Specifies the code defined by a terminology system.\n        type: array\n        items: Coding\n      text?:\n        description: Represents the meaning of the codeable concept as text.\n        type: string\n  canonical:\n    type: uri\n    description: |\n      A URI that refers to a resource by its canonical URL, which are the resources with a URL property. The canonical type differs from a URI and can have a version appended that\'s separated by a vertical bar (|). The type canonical isn\'t used for the actual canonical URLs that are the target of these references, but for the URIs that refer to them, and can have the version suffix in them. Like other URIs, elements of type canonical can also have #fragment references.\n           \n  Coding:\n    type: object\n    description: |\n      Represents a defined concept using a symbol from a defined code system.\n      See <a href=\"http://hl7.org/fhir/STU3/terminologies.html\" target=\"_blank\">Terminologies</a>.\n    properties:\n      system?:\n        description: Specifies the identity of the terminology system.\n        type: uri\n      version?:\n        description: Specifies the version of the system, if relevant.\n        type: string\n      code?:\n        description: Specifies the symbol in the syntax that\'s defined by the system.\n        type: code\n      display?:\n        description: Specifies the representation defined by the system.\n        type: string\n  ContactPoint:\n    type: Element\n    description: |\n      Provides details for different technology-mediated contact points for a person or organization, including telephone or email.\n    properties:\n      system?:\n        type: code\n        enum: [phone,fax,email,sms,pager,url,other]\n      value?:\n        description: Specifies the actual contact point details.\n        type: string\n      use?:\n        description: Specifies the purpose of the contact point.\n        type: code\n        enum: [home, work, temp, old, mobile]\n      rank?:\n        description: Specifies the preferred order of use (1 = highest).\n        type: positiveInt\n      period?:\n        description: Specifies the time period when the contact point was or is in use\n        type: Period\n           \n  dateTime:\n    type: string\n    description: |\n      Specifies a date, date and time, or partial date (year or year with month). If hours and minutes are specified, a time zone is populated.\n      Seconds must be provided due to schema type constraints but allows zero-filled values. Dates must be valid dates. The time, \"24:00\" isn\'t allowed.\n    pattern: ^[0-9]{4}(-(0[1-9]|1[0-2])(-(0[0-9]|[1-2][0-9]|3[0-1])(T([01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9](\\.[0-9]+)?(Z|(\\+|-)((0[0-9]|1[0-3]):[0-5][0-9]|14:00)))?)?)?$\n \n  Element:\n    type: object\n    properties:\n      id?:\n        description: Specifies the internal ID of the element.\n        type: id\n        \n  Extension:\n    type: Element\n    description: |\n      Optional. Specifies the extensions element and rule. Must have either extensions or value[x], but not both elements defined in the ancestors ID or extension.\n    properties:\n      url:\n        type: uri\n        description: Identifies the meaning of the extension.\n      value?:\n        description: Specifies the value of the extension.\n\n  Entry: \n    type: object\n    description: |\n      An entry in the bundle includes a resource or information.\n      + Rule: The entry must be a resource unless there\'s a request or response.\n      + Rule: The fullUrl property can\'t be a version-specific reference.\n      For bundles of the document and message types, the first resource must be Composition and MessageHeader resources, respectively. For all bundles, the meaning of the order of entries depends on the bundle type.\n    properties:\n      fullUrl?:\n        type: uri\n        description: Specifies the URI for the resource, which is the absolute URL server address, or the URI for UUID or OID.\n      search?:\n        description: Provides the search-related information.\n        properties:\n          mode?:\n            description: Specifies the search mode and criteria. Possible values are match, include, and outcome.\n            type: code\n            enum: [match, include, outcome]\n      resource?:\n        type: Resource\n        description: Specifies a resource in the bundle.\n        \n  HumanName:\n    type: Element\n    description: |\n      Specifies the name of a human with text, parts, and usage information.\n    properties:\n      use?:\n        type: code\n        enum: [usual, official ,temp, nickname, anonymous, old, maiden]\n      text?:\n        type: string\n        description: Specifies the text representation of the full name.\n      family?:\n        description: Specifies the family name or the surname.\n        type: string\n      given?:\n        description: Specifies the given names, which includes middle names and not always the first name. \n        type: string[]\n      prefix?:\n        description: Specifies the parts that come before the name.\n        type: string[]\n      suffix?:\n        description: Specifies the parts that come after the name.\n        type: string[]\n      period?:\n        description: Specifies the time period when the name was or is in use.\n        type: Period\n                \n  \n      \n      \n  Identifier:\n    description: |\n      Represents a numeric or alphanumeric string that\'s associated with a single object or entity within a given system.\n      Typically, identifiers are used to connect the content in the resources to external content available in other frameworks or protocols.\n      Identifiers are associated with objects and can change or retire due to human or system processes and errors.\n    properties:\n      use?:\n        description: usual | official | temp | secondary (If known)\n        type: code\n        enum: [usual, official, temp, secondary, old]\n      type?:\n        description: Describes the identifier.\n        type: CodeableConcept\n      system?:\n        description: Provides the namespace for the identifier value.\n        type: uri\n      value?:\n        description: Specifies the ID value of the identifier.\n        type: string\n      period?:\n        description: Specifies the time period when the ID is or was valid for use.\n        type: Period\n      assigner?:\n        description: Specifies the organization that issued the ID. \n        type: Reference \n        \n  instant:\n    type: string\n    description: |\n      Represents an instant in time that\'s known at least to the second and always includes a time zone.\n      Note: An instant in time is intended for precisely observed times, such as system logs, and not human-reported times. Use date and dateTime for human-reported times. Instant is a more constrained dateTime.\n      Note: An instant in time is for system times, not human-reported times, such as date and dateTime.\n    pattern: ^[0-9]{4}(-(0[1-9]|1[0-2])(-(0[0-9]|[1-2][0-9]|3[0-1])(T([01][0-9]|2[0-3]):[0-5][0-9]:[0-5][0-9](\\.[0-9]+)?(Z|(\\+|-)((0[0-9]|1[0-3]):[0-5][0-9]|14:00)))))$\n  \n  \n\n  Period:\n    type: Element\n    description: Specifies a time period defined by a start and end date or time.\n    properties:\n      start?:\n        description: Specifies the starting time with inclusive boundary.\n        type: dateTime\n      end?:\n        description: Specifies the end time with inclusive boundary, if not ongoing.\n        type: dateTime\n        \n  Quantity:\n    type: Element\n    description: Specifies a measured amount or an amount that can potentially be measured.\n    properties:\n      value?:\n        description: Specifies the numerical value with implicit precision.\n        type: decimal\n      comparator?:\n        description: Specifies the method to understand the value.\n        type: code\n        enum: [\'<\', \'<=\', \'>=\', \'>\']\n      unit?:\n        description: Specifies the unit representation.\n        type: string\n      system?:\n       description: Specifies the system that defines the coded unit form.\n       type: uri\n      code?:\n        description: Specifies the coded form of the unit.\n        type: code\n        \n  OperationOutcome:\n    description: Provides information about the success or failure of an action. Elements are defined in ancestors id, meta, implicitRules, language, text, contained, extension, and modifierExtension.\n    properties:\n      issue:\n        type: array\n        description: \n        items:\n          properties:\n            severity:\n              type: code\n              description: Specifies the severity of the issue. Possible values are fatal,  error, warning, and information.\n              enum: [fatal , error , warning , information]\n            code:\n              type: code\n              description: Error or warning code\n              enum: [invalid, structure, required, value, invariant, security, login, unknown, expired, forbidden, suppressed, processing, not-supported, duplicate, multiple-matches, not-found, deleted, too-long, code-invalid, extension, too-costly, business-rule, conflict, transient, lock-error, no-store, exception, timeout, incomplete, throttled, informational]\n            details?:\n              type: CodeableConcept\n              description: Additional details about the error\n                \n  Reference:\n    type: Element\n    description: Specifies the defined elements in a resource that are references to other resources.\n      Using the references, the resources combine to build a web of information about healthcare.\n    properties:\n      reference?:\n        description: Specifies a literal, relative, internal, or absolute URL reference.\n        type: string   \n\n  Resource:\n    description: Specifies the base resource.\n    properties:\n      id?:\n        description: Specifies the ID of the base resource.\n        type: id\n      meta?:\n        description: Specifies the metadata about the resource.\n        type: Meta\n      implicitRules?:\n        description: Specifies a set of rules that\'s used to create the content.\n        type: uri\n      language?:\n        description: Specifies the language of th